import{_ as r,o as a,c as t,ae as i}from"./chunks/framework.B6gjLfeO.js";const d=JSON.parse('{"title":"SMS","description":"","frontmatter":{"title":"SMS","slug":"sms"},"headers":[],"relativePath":"marketer-hub/sms.md","filePath":"marketer-hub/sms.md"}'),n={name:"marketer-hub/sms.md"};function o(l,e,s,c,h,u){return a(),t("div",null,[...e[0]||(e[0]=[i('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>SMS continues to be a reliable channel to acquire/engage your users into your platform where they receive the best possible experience with your brand. Typical campaigns are effective, but they can be difficult to properly track.</p><p>Branch can be used to help power your SMS campaigns through the use of Branch Links.</p><h3 id="sms-use-cases" tabindex="-1">SMS Use Cases <a class="header-anchor" href="#sms-use-cases" aria-label="Permalink to &quot;SMS Use Cases&quot;">​</a></h3><ul><li>Programmatic Branch Link creation for sending through your SMS provider</li><li>Drive users from Desktop Web to app via SMS</li><li>Re-engage current users on new product launches, sales, etc.</li><li>Attribute downstream app events to SMS campaigns</li></ul><h2 id="how-does-it-work" tabindex="-1">How does it work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How does it work?&quot;">​</a></h2><ol><li>User receives an SMS</li><li>App opens<br> -The user may be routed to the App/Play Store if they don&#39;t already have your app installed</li><li>User is deep-linked into specific app content</li><li>Events (ex. purchases, sign-ups, etc.) are attributed back to SMS campaign</li></ol><h2 id="access" tabindex="-1">Access <a class="header-anchor" href="#access" aria-label="Permalink to &quot;Access&quot;">​</a></h2><p>Access to Branch Deep Links and the Deep Linking API requires a premium plan. Please <a href="https://www.branch.io/contact-sales/" target="_blank" rel="noreferrer">contact our Sales team</a> to learn more about pricing and availability.</p><h2 id="integration-guide" tabindex="-1">Integration Guide <a class="header-anchor" href="#integration-guide" aria-label="Permalink to &quot;Integration Guide&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Developer Required</p><p>Developers knowledgeable with APIs, Web, and Mobile Development may be required.</p></div><h4 id="_1-capture-the-users-phone-number" tabindex="-1">1. Capture the users&#39; phone number <a class="header-anchor" href="#_1-capture-the-users-phone-number" aria-label="Permalink to &quot;1. Capture the users&#39; phone number&quot;">​</a></h4><p>This can be in the form of an input/text field on your website, through a mailing list/database, etc.</p><h4 id="_2-create-configure-your-branch-link" tabindex="-1">2. Create &amp; Configure your Branch Link <a class="header-anchor" href="#_2-create-configure-your-branch-link" aria-label="Permalink to &quot;2. Create &amp; Configure your Branch Link&quot;">​</a></h4><p>Branch Link creation options:</p><ul><li><p><a href="./create-quick-links.html">Short Link</a></p><ul><li>Ideal for one-off campaigns</li></ul></li><li><p><a href="./deep-linking-api.html">Deep Linking API</a></p><ul><li>Ideal if you are looking to programmatically generate Branch Links at scale</li></ul></li><li><p><a href="./native-sdks-overview.html">Mobile SDKs</a></p></li><li><p><a href="./web-sdk-overview.html">Web SDK</a></p></li><li><p><a href="https://chrome.google.com/webstore/detail/branch-link-creator/pekdpppibljpmpbcjelehhnldnfbglgf" target="_blank" rel="noreferrer">Chrome Extension</a></p></li></ul><p>Additional information on configuring your Branch Link can be found <a href="./creating-a-deep-link.html">here</a>.</p><h4 id="_3-include-the-generated-branch-link-in-the-sms-sent-to-the-user-by-your-sms-service-provider" tabindex="-1">3. Include the generated Branch Link in the SMS sent to the user by your SMS service provider <a class="header-anchor" href="#_3-include-the-generated-branch-link-in-the-sms-sent-to-the-user-by-your-sms-service-provider" aria-label="Permalink to &quot;3. Include the generated Branch Link in the SMS sent to the user by your SMS service provider&quot;">​</a></h4><p>SMS Service Providers:</p><ul><li><a href="https://www.twilio.com/messaging/sms" target="_blank" rel="noreferrer">Twilio</a></li><li><a href="https://www.salesforce.com/products/marketing-cloud/overview/" target="_blank" rel="noreferrer">Salesforce Marketing Cloud</a></li><li><a href="https://www.clickatell.com/" target="_blank" rel="noreferrer">Clickatell</a></li><li><a href="https://www.clicksend.com/us/" target="_blank" rel="noreferrer">ClickSend</a></li><li><a href="https://www.burstsms.com/" target="_blank" rel="noreferrer">BurstSMS</a></li></ul>',20)])])}const m=r(n,[["render",o]]);export{d as __pageData,m as default};
